+                        const td = h('td', tdClass ? { className: tdClass } : null);
+                        td.appendChild(renderCell(entry, col));
+                        row.appendChild(td);
+                    }
+                    tbody.appendChild(row);
+                    prevEntry = entry;
+                    prevGroupKey = groupKey;
+                }
+            } else {
