+                    if (prevEntry) {
+                        if (!prevEntry.passed && entry.passed) rowClass = 'history-improved';
+                        else if (prevEntry.passed && !entry.passed) rowClass = 'history-regressed';
+                    }
+
+                    const row = h('tr', rowClass ? { className: rowClass } : null);
